object Solution { def parse_csv_row(line: String): Seq[String] = { val fields = scala.collection.mutable.ArrayBuffer[String](); val current = new StringBuilder; var inQuotes = false; var index = 0; while (index < line.length) { val ch = line.charAt(index); if (inQuotes) { if (ch == '"') { if (index + 1 < line.length && line.charAt(index + 1) == '"') { current.append('"'); index += 2 } else { inQuotes = false; index += 1 } } else { current.append(ch); index += 1 } } else if (ch == '"' && current.isEmpty) { inQuotes = true; index += 1 } else if (ch == ',') { fields += current.toString; current.clear(); index += 1 } else { current.append(ch); index += 1 } }; fields += current.toString; fields.toSeq } }
